import{_ as t,o,c as a,ag as r}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"WeCom (WeWork) Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/wecom.md","filePath":"channels/wecom.md","lastUpdated":1774787421000}'),n={name:"channels/wecom.md"};function i(s,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="wecom-wework-channel-configuration" tabindex="-1">WeCom (WeWork) Channel Configuration <a class="header-anchor" href="#wecom-wework-channel-configuration" aria-label="Permalink to &quot;WeCom (WeWork) Channel Configuration&quot;">​</a></h1><p>Connecting your Memoh Bot to WeCom (企业微信) allows it to interact with users within your organization&#39;s WeCom workspace.</p><h2 id="step-1-create-a-wecom-bot" tabindex="-1">Step 1: Create a WeCom Bot <a class="header-anchor" href="#step-1-create-a-wecom-bot" aria-label="Permalink to &quot;Step 1: Create a WeCom Bot&quot;">​</a></h2><ol><li>Log in to the <a href="https://work.weixin.qq.com/" target="_blank" rel="noreferrer">WeCom Admin Console</a>.</li><li>Navigate to <strong>App Management</strong> &gt; <strong>Custom Apps</strong> or <strong>Bot Management</strong>.</li><li>Create a new bot application.</li><li>Note the <strong>Bot ID</strong> and <strong>Secret</strong> credentials.</li></ol><h2 id="step-2-configure-memoh" tabindex="-1">Step 2: Configure Memoh <a class="header-anchor" href="#step-2-configure-memoh" aria-label="Permalink to &quot;Step 2: Configure Memoh&quot;">​</a></h2><ol><li>Go to your Bot&#39;s <strong>Platforms</strong> tab in the Memoh Web UI.</li><li>Click <strong>Add Channel</strong> and select <strong>WeCom</strong>.</li><li>Fill in the required fields:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Bot ID</strong></td><td>Yes</td><td>The WeCom bot identifier.</td></tr><tr><td><strong>Secret</strong></td><td>Yes</td><td>The bot&#39;s authentication credential.</td></tr><tr><td><strong>WebSocket URL</strong></td><td>No</td><td>Custom WebSocket endpoint (uses default if empty).</td></tr></tbody></table><ol start="4"><li>Click <strong>Save and Enable</strong>.</li></ol><h2 id="step-3-start-chatting" tabindex="-1">Step 3: Start Chatting <a class="header-anchor" href="#step-3-start-chatting" aria-label="Permalink to &quot;Step 3: Start Chatting&quot;">​</a></h2><p>Once the channel is enabled, the bot will connect to WeCom via WebSocket and begin receiving messages. Users in your WeCom workspace can send messages to the bot directly or in group chats.</p><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Message Content</strong>: Full support for text messages.</li><li><strong>Direct Messages</strong>: Private conversations with individual users.</li><li><strong>Group Chats</strong>: Participate in group conversations.</li><li><strong>Streaming</strong>: Responses are streamed in real-time.</li></ul><h2 id="official-resources" tabindex="-1">Official Resources <a class="header-anchor" href="#official-resources" aria-label="Permalink to &quot;Official Resources&quot;">​</a></h2><ul><li><a href="https://developer.work.weixin.qq.com/" target="_blank" rel="noreferrer">WeCom Open Platform</a></li><li><a href="https://developer.work.weixin.qq.com/document/path/91770" target="_blank" rel="noreferrer">WeCom Bot Documentation</a></li></ul>',14)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
